using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains an ML.NET multiclass classification model and saves it to disk.
/// </summary>
public static class TicketModelTrainer
{
    /// <summary>
    /// Trains the model, logs evaluation metrics, and saves it to disk.
    /// Returns the path to the saved model and the ordered label names.
    /// </summary>
    public static (string ModelPath, string[] Labels) TrainAndEvaluate(
        string dataPath, string modelPath, ILogger logger)
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Featurise text columns and combine with the numeric priority column
        var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label")
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        logger.LogInformation("Training ticket classification model...");
        ITransformer model = pipeline.Fit(split.TrainSet);

        // Extract label names in key order from the trained model's output schema
        var outputSchema = model.GetOutputSchema(split.TrainSet.Schema);
        var labelColumn = outputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetSlotNames(ref slotNames);
        string[] labels = slotNames.DenseValues()
            .Select(v => v.ToString())
            .ToArray();

        // Evaluate on the held-out test set
        IDataView predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        logger.LogInformation("=== Model Evaluation Metrics ===");
        logger.LogInformation("Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);
        logger.LogInformation("Confusion matrix:\n{Matrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        mlContext.Model.Save(model, data.Schema, modelPath);
        logger.LogInformation("Model saved to {Path}", modelPath);

        return (modelPath, labels);
    }
}

