using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train the model at startup so the pool can load it
using var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
var logger = loggerFactory.CreateLogger("TicketModelTrainer");

string dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
string modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");
var (_, labels) = TicketModelTrainer.TrainAndEvaluate(dataPath, modelPath, logger);

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

// Register the label names so the controller can map scores to categories
builder.Services.AddSingleton(new LabelMetadata(labels));

var app = builder.Build();
app.MapControllers();
app.Run();

